/**
 * @test Mutex_Init_ValidParameters_Success
 * @brief 测试正常初始化互斥量
 * @details 验证互斥量初始化后所有字段是否正确设置
 * @Given 有效的互斥量指针和名称
 * @When 调用 mrtk_mutex_init()
 * @Then 返回 MRTK_EOK，互斥量状态正确
 */
TEST_F(MrtkMutexTest, Mutex_Init_ValidParameters_Success) {
    // Step 1: Given - 准备有效的互斥量对象和参数
    const mrtk_char_t *mutex_name = "TestMutex";
    mrtk_u8_t flag = MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO;

    // Step 2: When - 执行初始化
    mrtk_err_t ret = mrtk_mutex_init(&test_mutex_static, mutex_name, flag);

    // Step 3: Then - 验证返回值和互斥量状态
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(test_mutex_static.value, MRTK_MUTEX_STATE_UNLOCKED);
    EXPECT_EQ(test_mutex_static.nest, 0);
    EXPECT_EQ(test_mutex_static.owner_task, nullptr);
    EXPECT_EQ(test_mutex_static.orig_prio, MRTK_INVALID_U8);
}

