/**
 * @test Mutex_Init_DifferentFlagTypes_Success
 * @brief 测试不同唤醒策略标志
 * @details 验证 FIFO 和 PRIO 两种唤醒策略都能正确初始化
 * @Given 有效的互斥量对象和不同的 flag 值
 * @When 分别使用 FIFO 和 PRIO 标志初始化
 * @Then 初始化成功，flag 值正确保存
 */
TEST_F(MrtkMutexTest, Mutex_Init_DifferentFlagTypes_Success) {
    // Step 1: Given - 有效的互斥量对象
    const mrtk_char_t *mutex_name = "TestMutex";

    // Step 2: When - 分别使用 FIFO 和 PRIO 标志初始化
    mrtk_err_t ret_fifo = mrtk_mutex_init(&test_mutex_static, mutex_name,
                                           MRTK_IPC_FLAG_NOTIFY_POLICY_FIFO);
    mrtk_err_t ret_prio = mrtk_mutex_init(&test_mutex_static, mutex_name,
                                           MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    // Step 3: Then - 两次初始化都应成功
    EXPECT_EQ(ret_fifo, MRTK_EOK);
    EXPECT_EQ(ret_prio, MRTK_EOK);
}

