/**
 * @test Mutex_Detach_ValidMutex_Success
 * @brief 测试正常脱离互斥量
 * @details 验证脱离静态互斥量后的状态
 * @Given 已初始化的静态互斥量
 * @When 调用 mrtk_mutex_detach()
 * @Then 返回 MRTK_EOK，所有等待任务被唤醒并设置错误码
 */
TEST_F(MrtkMutexTest, Mutex_Detach_ValidMutex_Success) {
    // Step 1: Given - 初始化互斥量
    mrtk_mutex_init(&test_mutex_static, "TestMutex",
                    MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    // Step 2: When - 脱离互斥量
    mrtk_err_t ret = mrtk_mutex_detach(&test_mutex_static);

    // Step 3: Then - 验证返回值
    EXPECT_EQ(ret, MRTK_EOK);
}

/**
 * @test Mutex_Detach_WithWaitingTasks_TasksResumedWithError
 * @brief 测试脱离有等待任务的互斥量
 * @details 验证脱离时唤醒所有等待任务并设置 MRTK_EDELETED 错误码
 * @Given 已初始化的互斥量，且有任务在等待队列中
 * @When 调用 mrtk_mutex_detach()
 * @Then 所有等待任务被唤醒，last_error 设置为 MRTK_EDELETED
 */
TEST_F(MrtkMutexTest, Mutex_Detach_WithWaitingTasks_TasksResumedWithError) {
    // Step 1: Given - 初始化互斥量，并让低优先级任务持有，高优先级任务等待
    mrtk_mutex_init(&test_mutex_static, "TestMutex",
                    MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    // 设置低优先级任务为当前运行任务并获取互斥量
    set_current_task(&task_low);
    make_task_ready(&task_low);
    mrtk_mutex_take(&test_mutex_static, 0);

    // 将高优先级任务挂起到互斥量的等待队列
    make_task_suspend(&task_high);
    _mrtk_list_insert_before(&test_mutex_static.ipc_obj.suspend_taker, &task_high.sched_node);

    // Step 2: When - 脱离互斥量
    mrtk_err_t ret = mrtk_mutex_detach(&test_mutex_static);

    // Step 3: Then - 验证返回值和高优先级任务的状态
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(task_high.last_error, MRTK_EDELETED);
    EXPECT_EQ(task_high.state, MRTK_TASK_STAT_READY); /* 被唤醒到就绪态 */
}

/**
 * @test Mutex_Detach_WithOwner_RestoresOriginalPriority
 * @brief 测试脱离有持有者的互斥量
 * @details 验证脱离时恢复持有者的原始优先级
 * @Given 互斥量被某个任务持有，且发生过优先级继承
 * @When 调用 mrtk_mutex_detach()
 * @Then 持有者的优先级恢复到原始值
 */
TEST_F(MrtkMutexTest, Mutex_Detach_WithOwner_RestoresOriginalPriority) {
    // Step 1: Given - 低优先级任务持有互斥量，原始优先级被提升
    mrtk_mutex_init(&test_mutex_static, "TestMutex",
                    MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    set_current_task(&task_low);
    make_task_ready(&task_low);
    mrtk_mutex_take(&test_mutex_static, 0);

    // 模拟优先级继承：提升低优先级任务的优先级
    test_mutex_static.orig_prio = PRIO_LOW;
    task_low.priority = PRIO_HIGH; /* 被提升 */

    // Step 2: When - 脱离互斥量
    mrtk_err_t ret = mrtk_mutex_detach(&test_mutex_static);

    mrtk_task_dump(&task_low);
    // Step 3: Then - 验证返回值和优先级恢复
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(task_low.priority, PRIO_LOW); /* 恢复到原始优先级 */
}

