/**
 * @test Mutex_Release_WithWaitingTasks_WakeupOneTask
 * @brief 测试释放时有等待任务的情况
 * @details 验证释放时唤醒一个等待任务并转移所有权
 * @Given 互斥量被持有，且有任务在等待队列中
 * @When 持有者释放互斥量
 * @Then 等待队列中的一个任务被唤醒，成为新的持有者
 */
TEST_F(MrtkMutexTest, Mutex_Release_WithWaitingTasks_WakeupOneTask) {
    // Step 1: Given - 低优先级任务持有互斥量，高优先级任务等待
    mrtk_mutex_init(&test_mutex_static, "TestMutex",
                    MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_low);
    make_task_ready(&task_low);
    mrtk_mutex_take(&test_mutex_static, 0);

    // 将高优先级任务挂起到等待队列
    make_task_suspend(&task_high);
    task_high.last_error = MRTK_EOK;
    _mrtk_list_insert_before(&test_mutex_static.ipc_obj.suspend_taker,
                          &task_high.sched_node);

    // Step 2: When - 低优先级任务释放互斥量
    mrtk_err_t ret = mrtk_mutex_release(&test_mutex_static);

    // Step 3: Then - 验证高优先级任务被唤醒并成为新持有者
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(test_mutex_static.owner_task, &task_high);
    EXPECT_EQ(test_mutex_static.nest, 1);
    EXPECT_EQ(test_mutex_static.orig_prio, PRIO_HIGH);
}

/**
 * @test Mutex_Release_RestoresOriginalPriority
 * @brief 测试释放时恢复持有者原始优先级
 * @details 验证互斥量释放后，持有者的优先级能够正确恢复到原始值
 * @Given 低优先级任务持有互斥量，且发生过优先级继承（优先级被提升）
 * @When 持有者任务释放互斥量
 * @Then 持有者的优先级恢复到原始值，互斥量状态正确
 */
TEST_F(MrtkMutexTest, Mutex_Release_RestoresOriginalPriority) {
    /* Step 1: Given - 低优先级任务持有互斥量，且发生过优先级继承 */
    mrtk_mutex_init(&test_mutex_static, "TestMutex",
                    MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    /* 低优先级任务获取互斥量 */
    set_current_task(&task_low);
    make_task_ready(&task_low);
    mrtk_mutex_take(&test_mutex_static, 0);

    /* 验证初始状态 */
    verify_mutex_state(&test_mutex_static, MRTK_MUTEX_STATE_LOCKED, 1, &task_low,
                       PRIO_LOW);
    verify_task_priority(&task_low, PRIO_LOW);
    EXPECT_EQ(task_low.orig_prio, PRIO_LOW); /* 原始优先级 */

    /* 模拟高优先级任务等待触发优先级继承 */
    /* 方法：手动提升低优先级任务的优先级，模拟优先级继承场景 */
    test_mutex_static.orig_prio = PRIO_LOW;  /* 互斥量记录的原始优先级 */
    task_low.priority         = PRIO_HIGH;   /* 被提升到高优先级 */

    /* 验证优先级已被提升 */
    verify_task_priority(&task_low, PRIO_HIGH);

    /* Step 2: When - 低优先级任务释放互斥量 */
    mrtk_err_t ret = mrtk_mutex_release(&test_mutex_static);

    mrtk_task_dump(&task_low);
    /* Step 3: Then - 验证返回值和优先级恢复 */
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(task_low.priority, PRIO_LOW);     /* 恢复到原始优先级 */
    EXPECT_EQ(task_low.orig_prio, PRIO_LOW);    /* 原始优先级不变 */

    /* 验证互斥量状态：已释放，无持有者 */
    verify_mutex_state(&test_mutex_static, MRTK_MUTEX_STATE_UNLOCKED, 0, nullptr,
                       MRTK_INVALID_U8);

    /* 验证任务不再持有互斥量（通过检查链表是否为空） */
    EXPECT_TRUE(_mrtk_list_is_empty(&task_low.held_mutex_list));
}

