/**
 * @test Mutex_CompleteLifecycle_InitTakeReleaseDetach_Success
 * @brief 测试互斥量完整生命周期
 * @details 验证 Init → Take → Release → Detach 的完整流程
 * @Given 互斥量对象
 * @When 依次执行 init, take, release, detach
 * @Then 每一步都成功返回
 */
TEST_F(MrtkMutexTest, Mutex_CompleteLifecycle_InitTakeReleaseDetach_Success) {
    // Step 1: Given - 互斥量对象和任务

    // Step 2: When - 执行完整生命周期
    mrtk_err_t ret_init = mrtk_mutex_init(&test_mutex_static, "LifecycleMutex",
                                           MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_high);
    make_task_ready(&task_high);
    mrtk_err_t ret_take = mrtk_mutex_take(&test_mutex_static, 100);
    mrtk_err_t ret_release = mrtk_mutex_release(&test_mutex_static);
    mrtk_err_t ret_detach = mrtk_mutex_detach(&test_mutex_static);

    // Step 3: Then - 验证每一步都成功
    EXPECT_EQ(ret_init, MRTK_EOK);
    EXPECT_EQ(ret_take, MRTK_EOK);
    EXPECT_EQ(ret_release, MRTK_EOK);
    EXPECT_EQ(ret_detach, MRTK_EOK);
}

/**
 * @test Mutex_MultipleTasksWaiting_PriorityOrderWakeup
 * @brief 测试多任务等待时的唤醒顺序
 * @details 验证 PRIO 策略下按优先级顺序唤醒
 * @Given 互斥量被持有，3 个不同优先级的任务在等待
 * @When 持有者释放互斥量
 * @Then 最高优先级的等待任务被唤醒
 */
TEST_F(MrtkMutexTest, Mutex_MultipleTasksWaiting_PriorityOrderWakeup) {
    /* Step 1: Given - 低优先级任务持有互斥量，3 个任务在等待队列 */

    /* 1.1 初始化互斥量并让低优先级任务持有 */
    mrtk_mutex_init(&test_mutex_static, "TestMutex",
                    MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_low);
    make_task_ready(&task_low);
    mrtk_mutex_take(&test_mutex_static, 0);

    /* 1.2 将三个任务按任意顺序挂起到等待队列
     *     使用 _mrtk_ipc_suspend_one() 并传入 MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO
     *     函数会自动按优先级降序排序队列（高优先级在头部）
     */
    make_task_ready(&task_mid);
    _mrtk_ipc_suspend_one(&test_mutex_static.ipc_obj.suspend_taker,
                          MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO, &task_mid);

    make_task_ready(&task_high);
    _mrtk_ipc_suspend_one(&test_mutex_static.ipc_obj.suspend_taker,
                          MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO, &task_high);

    /* 创建另一个低优先级任务 */
    mrtk_task_t task_low_2;
    mrtk_u32_t task_stack_low_2[512];
    mrtk_task_init("TaskLow2", &task_low_2, dummy_task_entry, nullptr,
                   task_stack_low_2, 512, PRIO_LOW + 1, 10);
    make_task_ready(&task_low_2);
    _mrtk_ipc_suspend_one(&test_mutex_static.ipc_obj.suspend_taker,
                          MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO, &task_low_2);

    /* Step 2: When - 持有者释放互斥量 */
    set_current_task(&task_low);  /* 确保在持有者任务的上下文 */
    mrtk_err_t ret = mrtk_mutex_release(&test_mutex_static);

    /* Step 3: Then - 验证高优先级任务被唤醒
     *     由于使用了 PRIO 策略，_mrtk_ipc_suspend_one() 会自动排序
     *     队列顺序应为：task_high -> task_mid -> task_low_2（按优先级降序）
     *     mrtk_mutex_release() 调用 _mrtk_ipc_resume_one() 从队列头部取任务
     *     因此应该唤醒 task_high（最高优先级）
     */
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(test_mutex_static.owner_task, &task_high);
    EXPECT_EQ(test_mutex_static.orig_prio, PRIO_HIGH);
}

/**
 * @test Mutex_FIFO_WaitingOrder_FIFOWakeup
 * @brief 测试 FIFO 策略下的唤醒顺序
 * @details 验证 FIFO 策略按等待顺序唤醒
 * @Given 使用 FIFO 策略的互斥量，多个任务在等待
 * @When 持有者释放互斥量
 * @Then 按照等待顺序（先来先得）唤醒任务
 */
TEST_F(MrtkMutexTest, Mutex_FIFO_WaitingOrder_FIFOWakeup) {
    // Step 1: Given - FIFO 策略互斥量，3 个任务按顺序等待
    mrtk_mutex_init(&test_mutex_static, "TestMutex",
                    MRTK_IPC_FLAG_NOTIFY_POLICY_FIFO);
    set_current_task(&task_low);
    make_task_ready(&task_low);
    mrtk_mutex_take(&test_mutex_static, 0);

    // 按顺序插入等待队列
    make_task_suspend(&task_mid);
    _mrtk_list_insert_before(&test_mutex_static.ipc_obj.suspend_taker,
                          &task_mid.sched_node);

    make_task_suspend(&task_high);
    _mrtk_list_insert_before(&test_mutex_static.ipc_obj.suspend_taker,
                          &task_high.sched_node);

    make_task_suspend(&task_low);
    _mrtk_list_insert_before(&test_mutex_static.ipc_obj.suspend_taker,
                          &task_low.sched_node);

    // Step 2: When - 持有者释放互斥量
    mrtk_err_t ret = mrtk_mutex_release(&test_mutex_static);

    // Step 3: Then - 验证第一个等待者（中优先级任务）被唤醒
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(test_mutex_static.owner_task, &task_mid);
    EXPECT_EQ(test_mutex_static.orig_prio, PRIO_MID);
}

/**
 * @test Mutex_InterruptContext_NonBlockingOperations_Only
 * @brief 测试中断上下文中的互斥量操作限制
 * @details 验证中断中只能进行非阻塞操作
 * @Given 在中断上下文中
 * @When 尝试阻塞操作 vs 非阻塞操作
 * @Then 阻塞操作返回错误，非阻塞操作成功
 */
/**
 * @test Mutex_InterruptContext_NonBlockingOperations_Only
 * @brief 测试中断上下文中只允许非阻塞操作
 * @details 验证中断上下文中只允许非阻塞获取，阻塞操作和释放都被禁止
 * @Given 中断上下文
 * @When 在中断中尝试各种操作
 * @Then 只有非阻塞获取成功，其他操作都返回 MRTK_E_IN_ISR
 */
TEST_F(MrtkMutexTest, Mutex_InterruptContext_NonBlockingOperations_Only) {
    /* Step 1: Given - 中断上下文 */
    set_interrupt_nest(1);
    mrtk_mutex_init(&test_mutex_static, "TestMutex",
                    MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_high);
    make_task_ready(&task_high);

    /* Step 2: When - 在中断中尝试各种操作 */
    mrtk_err_t ret_nonblock = mrtk_mutex_take(&test_mutex_static, 0);   /* 允许：非阻塞 */
    mrtk_err_t ret_block    = mrtk_mutex_take(&test_mutex_static, 100); /* 禁止：阻塞 */
    mrtk_err_t ret_release  = mrtk_mutex_release(&test_mutex_static);  /* 禁止：释放 */

    /* Step 3: Then - 验证结果 */
    EXPECT_EQ(ret_nonblock, MRTK_EOK);         /* 非阻塞获取成功 */
    EXPECT_EQ(ret_block, MRTK_E_IN_ISR);       /* 阻塞获取被禁止 */
    EXPECT_EQ(ret_release, MRTK_E_IN_ISR);     /* 释放也被禁止（互斥量不适合中断） */

    /* 恢复中断嵌套 */
    set_interrupt_nest(0);
}

